_G.gameName    		      = "STICK\nHERO"-- Enter your app name \n means new line
_G.backgroundMusic        = true -- Enter true or false to enable or disable background music
_G.backgroundMusicNumber  = 3 -- Enter the number of random background music for example if you need to change it to 4 make sure to add bg4.mp3 to the sounds folder
_G.backgroundNumber       = 5 -- Enter the number of random backgrounds for example if you need to change it to 6 make sure to add bg6.png and shape6.png to the images folder
_G.platformWidth          = {10,100} -- Enter the minimum and the maximum width of the platform
_G.platformGap            = {40,140} -- Enter the minimum and the maximum gap of the platform
_G.useLeaderboard         = false -- Enter true or false to use leaderboard in build.settings change googlePlayGamesAppId = 00000000000, to your google play App ID (if needed)
_G.leaderboardCategoryID  = "" -- Enter your app leaderboard category id (if needed)
_G.showAds			      = false -- Enter true or false to enable or disable Admob
_G.admobInterstitialID    = "" -- Enter your Admob Interstitial ID  (if needed)
_G.admobBannerID          = "" -- Enter your Admob Banner ID  (if needed)
_G.failBeforeInterstitial = 3 -- number of fails before showing the Interstitial (if needed)
_G.iOSAppId               = 0 -- Enter your app id here. Used on the rate appstore popup (if needed)
_G.nookAppEAN             = 0 -- Enter your nook app EAN here. (if needed)